import React, { useState } from 'react';
import Input from './components/Input';
import Button from './components/Button';
import PersonaCard from './components/PersonaCard';
import { generatePersonaText, generatePersonaImage } from './services/gemini';
import { GeneratedPersona, PersonaInput } from './types';

const App: React.FC = () => {
  const [formData, setFormData] = useState<PersonaInput>({
    targetMarket: '',
    mainGoal: '',
    biggestFrustration: '',
  });

  const [generatedPersona, setGeneratedPersona] = useState<GeneratedPersona | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setGeneratedPersona(null);

    try {
      // Step 1: Generate Text (Name & Bio)
      const personaText = await generatePersonaText(formData);

      // Step 2: Generate Image based on visual description
      const imageUrl = await generatePersonaImage(personaText.visualDescription);

      // Combine results
      setGeneratedPersona({
        ...personaText,
        imageUrl,
      });
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate persona. Please check your API key and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 selection:bg-indigo-500/30">

      {/* Header Background Effect */}
      <div className="fixed top-0 left-0 right-0 h-96 bg-gradient-to-b from-indigo-900/20 to-transparent -z-10 pointer-events-none" />

      <main className="container mx-auto px-4 py-12 md:py-20 flex flex-col items-center gap-12">

        {/* Header */}
        <div className="text-center space-y-4 max-w-2xl">
          <h1 className="text-4xl md:text-6xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            PersonaGen AI
          </h1>
          <p className="text-lg text-slate-400">
            Instantly create detailed user personas with unique AI-generated avatars.
            Refine your marketing strategy in seconds.
          </p>
        </div>

        {/* Form */}
        <div className="w-full max-w-md bg-slate-900/50 backdrop-blur-sm border border-slate-800 rounded-2xl p-6 shadow-2xl">
          <form onSubmit={handleGenerate} className="space-y-6">
            <Input
              id="targetMarket"
              name="targetMarket"
              label="Target Market"
              placeholder="e.g. Freelance Graphic Designers"
              value={formData.targetMarket}
              onChange={handleInputChange}
              required
            />

            <Input
              id="mainGoal"
              name="mainGoal"
              label="Main Goal"
              placeholder="e.g. Increase recurring monthly revenue"
              value={formData.mainGoal}
              onChange={handleInputChange}
              required
            />

            <Input
              id="biggestFrustration"
              name="biggestFrustration"
              label="Biggest Frustration"
              placeholder="e.g. Inconsistent client acquisition"
              value={formData.biggestFrustration}
              onChange={handleInputChange}
              required
            />

            <Button type="submit" isLoading={isLoading}>
              Generate Persona
            </Button>
          </form>

          {error && (
            <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm text-center">
              {error}
            </div>
          )}
        </div>

        {/* Results */}
        {generatedPersona && (
          <div className="w-full animate-fade-in-up">
             <PersonaCard data={generatedPersona} />
          </div>
        )}

      </main>

      <style>{`
        @keyframes fade-in-up {
          from {
            opacity: 0;
            transform: translateY(20px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
        .animate-fade-in-up {
          animation: fade-in-up 0.6s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import html2canvas from 'html2canvas';
import { GeneratedPersona } from '../types';

interface PersonaCardProps {
  data: GeneratedPersona;
}

const PersonaCard: React.FC<PersonaCardProps> = ({ data }) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  const handleExportJSON = () => {
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `persona-${data.name.replace(/\s+/g, '-').toLowerCase()}.json`;
    document.body.appendChild(link);
    link.click();

    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportImage = async () => {
    if (!cardRef.current) return;

    setIsExporting(true);
    try {
      // Small delay to ensure any rendering is complete
      await new Promise(resolve => setTimeout(resolve, 100));

      const canvas = await html2canvas(cardRef.current, {
        useCORS: true,
        backgroundColor: '#1e293b', // Match bg-slate-800 for cleaner edges
        scale: 2, // Higher resolution
        logging: false,
      });

      const image = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = image;
      link.download = `persona-${data.name.replace(/\s+/g, '-').toLowerCase()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (error) {
      console.error('Error exporting image:', error);
      alert('Failed to export image.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto flex flex-col gap-4 animate-fade-in">
      {/* Capture Target */}
      <div 
        ref={cardRef} 
        className="bg-slate-800 rounded-2xl p-6 md:p-8 shadow-xl border border-slate-700 flex flex-col md:flex-row gap-8 items-center md:items-start"
      >
        <div className="flex-shrink-0 w-48 h-48 md:w-64 md:h-64 relative">
          <div className="absolute inset-0 bg-indigo-500 blur-2xl opacity-20 rounded-full"></div>
          <img
            src={data.imageUrl}
            alt={data.name}
            crossOrigin="anonymous" 
            className="relative w-full h-full object-cover rounded-xl shadow-2xl border-2 border-slate-600/50"
          />
        </div>

        <div className="flex-1 text-center md:text-left space-y-4">
          <div>
            <h2 className="text-3xl font-bold text-white tracking-tight mb-1">{data.name}</h2>
            <div className="inline-block px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 text-xs font-semibold uppercase tracking-wider">
              Target Persona
            </div>
          </div>

          <div className="space-y-2">
              <h3 className="text-sm font-medium text-slate-400 uppercase tracking-wide">Bio</h3>
              <p className="text-slate-300 leading-relaxed text-sm md:text-base">
              {data.bio}
              </p>
          </div>
        </div>
      </div>

      {/* Action Buttons */}
      <div className="flex flex-row justify-end gap-3">
        <button
          onClick={handleExportJSON}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-300 bg-slate-800 hover:bg-slate-700 hover:text-white border border-slate-700 rounded-lg transition-colors shadow-sm"
          title="Export as JSON"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><path d="M10 13l-2 2 2 2"/><path d="M14 17l2-2-2-2"/></svg>
          Export JSON
        </button>

        <button
          onClick={handleExportImage}
          disabled={isExporting}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-500 rounded-lg transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
          title="Download Card Image"
        >
           {isExporting ? (
            <svg className="animate-spin h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
          )}
          Download Image
        </button>
      </div>
    </div>
  );
};

export default PersonaCard;
